    {
      "input": {
        "deploy": {
          "service": "app",
          "image": "dhh/app",
          "registry": {
            "username": "dhh",
            "password": "secret"
          },
          "servers": [
            "1.1.1.1"
          ],
          "env": {
            "secret": [
              "RAILS_MASTER_KEY"
            ]
          }
        },
        "env": {
          "RAILS_MASTER_KEY": "456"
